sql:
SELECT run_id
FROM optimization_runs
WHERE run_status = 'completed';

SELECT run_id
FROM optimization_runs
WHERE planning_units = (SELECT MAX(planning_units) FROM optimization_runs);

SELECT MAX(run_duration) AS max_duration
  FROM optimization_runs
  WHERE run_status = 'completed';

SELECT run_id, MAX(run_duration) AS longest_duration
FROM optimization_runs
GROUP BY run_id;

SELECT unit_name
FROM planning_units
WHERE unit_status = 'active';

SELECT COUNT(run_id) 
FROM shortfalls 
WHERE shortfall_status = 'resolved';

SELECT run_id
FROM optimization_runs
WHERE mpm = (SELECT MAX(mpm) FROM optimization_runs);

SELECT run_id, score
FROM optimization_runs
ORDER BY score DESC;

SELECT COUNT(unit_id) AS active_unit_count
FROM planning_units
WHERE unit_status = 'active';

SELECT score
FROM optimization_runs
WHERE run_id = 1;

SELECT run_id
FROM penalties
WHERE penalty_value > 0;

